import{_ as n,o as r,c as o,am as s,j as t,a,bO as l,bP as i,bQ as p}from"./chunks/framework.yzuB8YhR.js";const f=JSON.parse('{"title":"FastAPI 交互式 API 文档","description":"","frontmatter":{},"headers":[],"relativePath":"编程/Python/FastAPI/04.交互式文档.md","filePath":"编程/Python/FastAPI/04.交互式文档.md","lastUpdated":1776923458000}'),d={name:"编程/Python/FastAPI/04.交互式文档.md"};function c(u,e,g,h,q,m){return r(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="fastapi-交互式-api-文档" tabindex="-1">FastAPI 交互式 API 文档 <a class="header-anchor" href="#fastapi-交互式-api-文档" aria-label="Permalink to “FastAPI 交互式 API 文档”">​</a></h1><p>FastAPI 基于代码中的类型注解自动生成交互式 API 文档，默认提供 Swagger UI 和 ReDoc 两种界面。开发者可以直接在文档中测试 API，无需额外的工具。</p><hr><h2 id="访问-api-文档" tabindex="-1">访问 API 文档 <a class="header-anchor" href="#访问-api-文档" aria-label="Permalink to “访问 API 文档”">​</a></h2><p>运行 FastAPI 应用后，访问以下地址查看文档：</p><table tabindex="0"><thead><tr><th style="text-align:left;">地址</th><th style="text-align:left;">文档类型</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><a href="http://127.0.0.1:8000/docs" target="_blank" rel="noreferrer">http://127.0.0.1:8000/docs</a></strong></td><td style="text-align:left;">Swagger UI</td><td style="text-align:left;">可交互测试，点击&quot;Try it out&quot;即可发送请求</td></tr><tr><td style="text-align:left;"><strong><a href="http://127.0.0.1:8000/redoc" target="_blank" rel="noreferrer">http://127.0.0.1:8000/redoc</a></strong></td><td style="text-align:left;">ReDoc</td><td style="text-align:left;">阅读体验好，适合浏览和查阅 API 定义</td></tr><tr><td style="text-align:left;"><strong><a href="http://127.0.0.1:8000/openapi.json" target="_blank" rel="noreferrer">http://127.0.0.1:8000/openapi.json</a></strong></td><td style="text-align:left;">OpenAPI JSON</td><td style="text-align:left;">原始的 OpenAPI 规范 JSON，可供工具消费</td></tr></tbody></table><hr><h2 id="swagger-ui" tabindex="-1">Swagger UI <a class="header-anchor" href="#swagger-ui" aria-label="Permalink to “Swagger UI”">​</a></h2><p>Swagger UI 提供了直观的用户界面，可以直接在浏览器中测试 API：</p><p><img src="'+l+'" alt="img"></p><h3 id="测试-api-的步骤" tabindex="-1">测试 API 的步骤 <a class="header-anchor" href="#测试-api-的步骤" aria-label="Permalink to “测试 API 的步骤”">​</a></h3><ol><li>点击要测试的路由，展开详情</li><li>点击 <strong>&quot;Try it out&quot;</strong> 按钮</li><li>填写参数值</li><li>点击 <strong>&quot;Execute&quot;</strong> 按钮发送请求</li><li>查看响应结果</li></ol><p><img src="'+i+'" alt="img"></p><hr><h2 id="redoc" tabindex="-1">ReDoc <a class="header-anchor" href="#redoc" aria-label="Permalink to “ReDoc”">​</a></h2><p>ReDoc 注重文档的可读性，适合浏览 API 定义：</p><p><img src="'+p+`" alt="img"></p><hr><h2 id="openapi-规范" tabindex="-1">OpenAPI 规范 <a class="header-anchor" href="#openapi-规范" aria-label="Permalink to “OpenAPI 规范”">​</a></h2><p>FastAPI 使用 <strong>OpenAPI</strong> 标准将 API 转换为&quot;模式&quot;（Schema）。访问 <strong><a href="http://127.0.0.1:8000/openapi.json" target="_blank" rel="noreferrer">http://127.0.0.1:8000/openapi.json</a></strong> 可以查看原始的 OpenAPI JSON：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;openapi&quot;: &quot;3.1.0&quot;,</span></span>
<span class="line"><span>    &quot;info&quot;: {</span></span>
<span class="line"><span>        &quot;title&quot;: &quot;FastAPI&quot;,</span></span>
<span class="line"><span>        &quot;version&quot;: &quot;0.1.0&quot;</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>    &quot;paths&quot;: {</span></span>
<span class="line"><span>        &quot;/items/{item_id}&quot;: {</span></span>
<span class="line"><span>            &quot;get&quot;: {</span></span>
<span class="line"><span>                &quot;responses&quot;: {</span></span>
<span class="line"><span>                    &quot;200&quot;: {</span></span>
<span class="line"><span>                        &quot;description&quot;: &quot;Successful Response&quot;</span></span>
<span class="line"><span>                    }</span></span>
<span class="line"><span>                }</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p>OpenAPI 规范的用途：</p><ul><li>驱动 Swagger UI 和 ReDoc 文档系统</li><li>自动生成各种语言的客户端代码</li><li>与 API 测试工具（如 Postman）集成</li><li>兼容大量第三方工具和平台</li></ul><hr><h2 id="自定义-api-文档信息" tabindex="-1">自定义 API 文档信息 <a class="header-anchor" href="#自定义-api-文档信息" aria-label="Permalink to “自定义 API 文档信息”">​</a></h2><p>创建 FastAPI 实例时，可以自定义文档的元数据：</p><h2 id="实例" tabindex="-1">实例 <a class="header-anchor" href="#实例" aria-label="Permalink to “实例”">​</a></h2><p><strong>from</strong> fastapi <strong>import</strong> FastAPI</p><p>app = FastAPI( title=&quot;我的 API&quot;, # API 标题 description=&quot;这是一个示例 API，展示文档自定义功能&quot;, # API 描述 version=&quot;1.0.0&quot;, # API 版本 terms_of_service=&quot;<a href="http://example.com/terms/" target="_blank" rel="noreferrer">http://example.com/terms/</a>&quot;, # 服务条款 URL contact={ # 联系信息 &quot;name&quot;: &quot;开发者&quot;, &quot;url&quot;: &quot;<a href="http://example.com/contact/" target="_blank" rel="noreferrer">http://example.com/contact/</a>&quot;, &quot;email&quot;: &quot;<a href="mailto:dev@example.com" target="_blank" rel="noreferrer">dev@example.com</a>&quot;, }, license_info={ # 许可证信息 &quot;name&quot;: &quot;MIT&quot;, &quot;url&quot;: &quot;<a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">https://opensource.org/licenses/MIT</a>&quot;, }, )</p><hr><h2 id="为路由添加文档信息" tabindex="-1">为路由添加文档信息 <a class="header-anchor" href="#为路由添加文档信息" aria-label="Permalink to “为路由添加文档信息”">​</a></h2><p>可以在装饰器和函数中为每个路由添加详细的文档信息：</p><h2 id="实例-1" tabindex="-1">实例 <a class="header-anchor" href="#实例-1" aria-label="Permalink to “实例”">​</a></h2><p><strong>from</strong> typing <strong>import</strong> Annotated <strong>from</strong> fastapi <strong>import</strong> FastAPI, Path, Query</p><p>app = FastAPI()</p><p>@app.get( &quot;/items/{item_id}&quot;, summary=&quot;获取商品信息&quot;, # 简短摘要 description=&quot;根据商品 ID 获取商品的详细信息&quot;, # 详细描述 response_description=&quot;商品信息对象&quot;, # 响应描述 tags=[&quot;商品管理&quot;], # 分组标签 ) async <strong>def</strong> read_item( item_id: Annotated[int, Path(ge=1, description=&quot;商品ID&quot;)], q: Annotated[str | None, Query(description=&quot;搜索关键词&quot;)] = None, ): &quot;&quot;&quot; 获取商品信息：</p>`,36),t("p",{"item_id:":"","item_id,":"","q:":"",q:""},[a("- "),t("strong",null,"item_id"),a(": 商品的唯一标识符 - "),t("strong",null,"q"),a(': 可选的搜索关键词 """ '),t("strong",null,"return")],-1),s('<p>文档参数说明：</p><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">位置</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>summary</code></td><td style="text-align:left;">装饰器</td><td style="text-align:left;">路由的简短摘要，显示在路由列表中</td></tr><tr><td style="text-align:left;"><code>description</code></td><td style="text-align:left;">装饰器</td><td style="text-align:left;">路由的详细描述，支持 Markdown</td></tr><tr><td style="text-align:left;"><code>response_description</code></td><td style="text-align:left;">装饰器</td><td style="text-align:left;">响应的描述</td></tr><tr><td style="text-align:left;"><code>tags</code></td><td style="text-align:left;">装饰器</td><td style="text-align:left;">路由分组，在文档中按标签分类显示</td></tr><tr><td style="text-align:left;">docstring</td><td style="text-align:left;">函数体</td><td style="text-align:left;">函数的文档字符串，会作为描述显示</td></tr></tbody></table><blockquote><p>如果同时设置了 <code>description</code> 和函数的 docstring，<code>description</code> 优先生效。docstring 支持 Markdown 格式，适合编写较长的说明。</p></blockquote><hr><h2 id="使用-tags-分组" tabindex="-1">使用 tags 分组 <a class="header-anchor" href="#使用-tags-分组" aria-label="Permalink to “使用 tags 分组”">​</a></h2><p><code>tags</code> 参数可以将相关的路由归为一组，在文档中更清晰地展示：</p><h2 id="实例-2" tabindex="-1">实例 <a class="header-anchor" href="#实例-2" aria-label="Permalink to “实例”">​</a></h2><p><strong>from</strong> fastapi <strong>import</strong> FastAPI</p><p>app = FastAPI()</p><p>@app.get(&quot;/users/&quot;, tags=[&quot;用户管理&quot;]) async <strong>def</strong> read_users(): <strong>return</strong> [{&quot;username&quot;: &quot;Rick&quot;}, {&quot;username&quot;: &quot;Morty&quot;}]</p><p>@app.get(&quot;/items/&quot;, tags=[&quot;商品管理&quot;]) async <strong>def</strong> read_items(): <strong>return</strong> [{&quot;name&quot;: &quot;Foo&quot;}, {&quot;name&quot;: &quot;Bar&quot;}]</p><p>在 Swagger UI 中，路由会按标签分组显示。</p><hr><h2 id="禁用文档" tabindex="-1">禁用文档 <a class="header-anchor" href="#禁用文档" aria-label="Permalink to “禁用文档”">​</a></h2><p>在生产环境中，你可能想禁用自动文档：</p><h2 id="实例-3" tabindex="-1">实例 <a class="header-anchor" href="#实例-3" aria-label="Permalink to “实例”">​</a></h2><p><strong>from</strong> fastapi <strong>import</strong> FastAPI</p><p># 禁用文档 app = FastAPI(docs_url=None, redoc_url=None)</p><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><ul><li>FastAPI 自动生成 Swagger UI 和 ReDoc 两种交互式文档</li><li>文档内容基于代码中的类型注解自动生成，代码更新文档自动同步</li><li>使用 <code>title</code>、<code>description</code>、<code>tags</code> 等参数自定义文档信息</li><li>函数的 docstring 也会出现在文档中</li><li>生产环境可通过 <code>docs_url=None</code> 禁用文档</li></ul>',21)])])}const P=n(d,[["render",c]]);export{f as __pageData,P as default};
